import {
  Component, Input, OnInit, OnDestroy, HostBinding,
  ChangeDetectorRef, ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { Subscription } from 'rxjs';
import { GoeyToastService } from './goey-toast.service';
import { GoeyToastComponent } from './goey-toast.component';
import { GoeyToastData, GoeyToastPosition } from './goey-toast.types';

@Component({
  selector: 'goey-toaster',
  standalone: true,
  imports: [CommonModule, GoeyToastComponent],
  templateUrl: './goey-toaster.component.html',
  styleUrls: ['./goey-toaster.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class GoeyToasterComponent implements OnInit, OnDestroy {
  @Input() position: GoeyToastPosition = 'bottom-right';
  @Input() duration?: number;
  @Input() gap = 14;
  @Input() offset: number | string = '24px';
  @Input() showClose = false;

  @Input() spring = true;
  @Input() bounce = 0.4;
  @Input() maxVisible = 5;

  toasts: GoeyToastData[] = [];
  private sub?: Subscription;

  @HostBinding('class')
  get positionClass(): string {
    return `goey-${this.position}`;
  }

  @HostBinding('style.padding')
  get offsetStyle(): string {
    const val = typeof this.offset === 'number' ? `${this.offset}px` : this.offset;
    return val;
  }

  get defaultFillColor(): string {
    return '#ffffff';
  }

  get defaultBorderColor(): string {
    return 'rgba(0,0,0,0.08)';
  }

  constructor(
    private toastService: GoeyToastService,
    private cdr: ChangeDetectorRef,
  ) {}

  ngOnInit(): void {
    // Push config to service
    this.toastService.setConfig({
      position: this.position,
      duration: this.duration,
      gap: this.gap,
      offset: this.offset,
      showClose: this.showClose,
      spring: this.spring,
      bounce: this.bounce,
      maxVisible: this.maxVisible,
    });

    this.sub = this.toastService.toasts.subscribe((toasts: GoeyToastData[]) => {
      this.toasts = toasts;
      this.cdr.detectChanges();
    });
  }

  ngOnDestroy(): void {
    this.sub?.unsubscribe();
  }

  trackById(_index: number, toast: GoeyToastData): string | number {
    return toast.id;
  }

  onToastDismissed(id: string | number): void {
    this.toastService.dismiss(id);
  }

  onActionClicked(toast: GoeyToastData): void {
    // Action handling is done in the toast component itself
  }
}
