import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import {
    GoeyToastData,
    GoeyToastType,
    GoeyToastOptions,
    GoeyToastPosition,
    GoeyPromiseData,
    GoeyToasterConfig,
} from './goey-toast.types';

@Injectable({ providedIn: 'root' })
export class GoeyToastService {
    private toasts$ = new BehaviorSubject<GoeyToastData[]>([]);
    private _config: GoeyToasterConfig = {
        position: 'bottom-right',
        duration: undefined,
        gap: 14,
        showClose: false,
        spring: true,
        bounce: 0.4,
        maxVisible: 5,
    };

    /** Observable of current toast stack */
    get toasts() {
        return this.toasts$.asObservable();
    }

    /** Current toast list snapshot */
    get currentToasts(): GoeyToastData[] {
        return this.toasts$.value;
    }

    /** Current global config */
    get config(): GoeyToasterConfig {
        return this._config;
    }

    /** Update global configuration */
    setConfig(config: Partial<GoeyToasterConfig>): void {
        this._config = { ...this._config, ...config };
    }

    /** Show a default toast */
    show(title: string, options?: GoeyToastOptions): string | number {
        return this.createToast(title, 'default', options);
    }

    /** Show a success toast */
    success(title: string, options?: GoeyToastOptions): string | number {
        return this.createToast(title, 'success', options);
    }

    /** Show an error toast */
    error(title: string, options?: GoeyToastOptions): string | number {
        return this.createToast(title, 'error', options);
    }

    /** Show a warning toast */
    warning(title: string, options?: GoeyToastOptions): string | number {
        return this.createToast(title, 'warning', options);
    }

    /** Show an info toast */
    info(title: string, options?: GoeyToastOptions): string | number {
        return this.createToast(title, 'info', options);
    }

    /** Show a promise toast: loading → success/error */
    promise<T>(promise: Promise<T>, data: GoeyPromiseData<T>): string | number {
        const id = this.generateId();
        const toastData: GoeyToastData = {
            id,
            title: data.loading,
            description: data.description?.loading,
            type: 'info',
            phase: 'loading',
            classNames: data.classNames,
            fillColor: data.fillColor,
            borderColor: data.borderColor,
            borderWidth: data.borderWidth,
            timing: data.timing,
            showClose: data.showClose,
            spring: data.spring,
            bounce: data.bounce,
            createdAt: Date.now(),
        };

        this.addToast(toastData);

        promise
            .then((result) => {
                const title = typeof data.success === 'function' ? data.success(result) : data.success;
                const desc = typeof data.description?.success === 'function'
                    ? data.description.success(result)
                    : data.description?.success;
                this.updateToast(id, {
                    title,
                    description: desc,
                    type: 'success',
                    phase: 'success',
                    action: data.action?.success,
                });
            })
            .catch((err) => {
                const title = typeof data.error === 'function' ? data.error(err) : data.error;
                const desc = typeof data.description?.error === 'function'
                    ? data.description.error(err)
                    : data.description?.error;
                this.updateToast(id, {
                    title,
                    description: desc,
                    type: 'error',
                    phase: 'error',
                    action: data.action?.error,
                });
            });

        return id;
    }

    /** Dismiss a specific toast or all toasts */
    dismiss(id?: string | number): void {
        const current = this.toasts$.value;
        if (id !== undefined) {
            const index = current.findIndex(t => t.id === id);
            if (index !== -1) {
                const toasts = [...current];
                toasts[index] = { ...toasts[index], dismissing: true };
                this.toasts$.next(toasts);
                setTimeout(() => {
                    this.toasts$.next(this.toasts$.value.filter((t: GoeyToastData) => t.id !== id));
                }, 300);
            }
        } else {
            const timeouts = current.map(t => {
                const toasts = [...this.toasts$.value];
                const i = toasts.findIndex(x => x.id === t.id);
                if (i !== -1) {
                    toasts[i] = { ...toasts[i], dismissing: true };
                    this.toasts$.next(toasts);
                }
                setTimeout(() => {
                     this.toasts$.next(this.toasts$.value.filter(x => x.id !== t.id));
                }, 300);
            });
        }
    }

    /** Update an existing toast's data */
    updateToast(id: string | number, partial: Partial<GoeyToastData>): void {
        const toasts = this.toasts$.value.map((t: GoeyToastData) =>
            t.id === id ? { ...t, ...partial } : t
        );
        this.toasts$.next(toasts);
    }

    private createToast(title: string, type: GoeyToastType, options?: GoeyToastOptions): string | number {
        const id = options?.id ?? this.generateId();
        const toastData: GoeyToastData = {
            id,
            title,
            type,
            phase: type,
            description: options?.description,
            action: options?.action,
            icon: options?.icon,
            classNames: options?.classNames,
            fillColor: options?.fillColor,
            borderColor: options?.borderColor,
            borderWidth: options?.borderWidth,
            timing: options?.timing,
            showClose: options?.showClose,
            spring: options?.spring,
            bounce: options?.bounce,
            duration: options?.duration,
            createdAt: Date.now(),
        };

        this.addToast(toastData);
        return id;
    }

    private addToast(toast: GoeyToastData): void {
        const current = this.toasts$.value;
        const maxVisible = this._config.maxVisible ?? 5;
        // Keep only the latest maxVisible toasts
        const updated = [...current, toast].slice(-maxVisible);
        this.toasts$.next(updated);
    }

    private generateId(): string {
        return Math.random().toString(36).slice(2);
    }
}
